import jwt
import datetime
from functools import wraps
from flask import Flask, request, jsonify, abort

class JWTAuth:
    def __init__(self, app=None, secret_key=None, expiration_minutes=60, algorithm='HS256'):
        self.secret_key = secret_key
        self.expiration_minutes = expiration_minutes
        self.algorithm = algorithm
        if app is not None:
            self.init_app(app)

    def init_app(self, app):
        if not self.secret_key:
            raise ValueError("JWTAuth requires a 'secret_key' to be set.")
        app.config['JWT_SECRET_KEY'] = self.secret_key
        app.config['JWT_EXPIRATION_MINUTES'] = self.expiration_minutes
        app.config['JWT_ALGORITHM'] = self.algorithm

    def create_token(self, user_id, **kwargs):
        payload = {
            'user_id': user_id,
            'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=self.expiration_minutes),
            'iat': datetime.datetime.utcnow()
        }
        payload.update(kwargs)
        return jwt.encode(payload, self.secret_key, algorithm=self.algorithm)

    def verify_token(self, token):
        try:
            payload = jwt.decode(token, self.secret_key, algorithms=[self.algorithm])
            return payload
        except jwt.ExpiredSignatureError:
            return None  # Token has expired
        except jwt.InvalidTokenError:
            return None  # Invalid token

    def login_required(self):
        def decorator(f):
            @wraps(f)
            def wrapper(*args, **kwargs):
                token = None
                if 'Authorization' in request.headers:
                    auth_header = request.headers['Authorization']
                    if auth_header.startswith('Bearer '):
                        token = auth_header.split(" ")[1]

                if not token:
                    abort(401, description="Token is missing.")

                payload = self.verify_token(token)
                if payload is None:
                    abort(401, description="Invalid or expired token.")

                request.user_id = payload.get('user_id')
                request.jwt_payload = payload
                return f(*args, **kwargs)
            return wrapper
        return decorator

if __name__ == '__main__':
    app = Flask(__name__)
    app.config['SECRET_KEY'] = 'your_super_secret_key_that_should_be_long_and_random' # Flask app secret

    # Initialize JWTAuth
    jwt_auth = JWTAuth(app, secret_key=app.config['SECRET_KEY'], expiration_minutes=30)

    # In a real application, you would have a user database
    # For simplicity, we'll use a dummy user store
    USERS = {
        'testuser': {'password': 'password123', 'id': 1},
        'admin': {'password': 'adminpass', 'id': 2}
    }

    @app.route('/')
    def index():
        return jsonify({"message": "Welcome to the JWT Auth API example!"})

    @app.route('/login', methods=['POST'])
    def login():
        data = request.get_json()
        username = data.get('username')
        password = data.get('password')

        user = USERS.get(username)

        if user and user['password'] == password:
            token = jwt_auth.create_token(user_id=user['id'], username=username, role='user')
            return jsonify({"token": token}), 200
        else:
            return jsonify({"message": "Invalid credentials"}), 401

    @app.route('/protected', methods=['GET'])
    @jwt_auth.login_required()
    def protected_route():
        # The user_id is now available in request.user_id
        # The full payload is in request.jwt_payload
        return jsonify({
            "message": f"Hello, user with ID {request.user_id}! You accessed a protected route.",
            "username_from_token": request.jwt_payload.get('username')
        }), 200

    @app.route('/admin_only', methods=['GET'])
    @jwt_auth.login_required()
    def admin_only_route():
        # You can add more complex authorization logic based on roles in the payload
        if request.jwt_payload.get('role') != 'admin':
            abort(403, description="Admin access required.")
        return jsonify({
            "message": f"Welcome, admin user {request.user_id}! You are in the admin zone.",
            "username_from_token": request.jwt_payload.get('username')
        }), 200

    @app.errorhandler(401)
    def unauthorized(error):
        return jsonify({"message": error.description or "Unauthorized access"}), 401

    @app.errorhandler(403)
    def forbidden(error):
        return jsonify({"message": error.description or "Forbidden access"}), 403

    app.run(debug=True) # Set debug=False in production